SELECT COUNT(1) FROM cms_content
AND category_code = #{categoryCode}
AND ( title LIKE concat('%', #{keyword}, '%') OR summary LIKE concat('%', #{keyword}, '%') OR author LIKE concat('%', #{keyword}, '%') OR source_name LIKE concat('%', #{keyword}, '%') )
AND EXISTS ( SELECT 1 FROM content_category_rel ccr JOIN knowledge_category kc ON kc.category_code = ccr.category_code WHERE ccr.content_id = cms_content.id AND kc.category_code = #{knowledgeCategoryCode} AND kc.status = 1 )
AND status = #{status}


WHERE status = 1
  AND category_code = #{categoryCode}
  AND publish_time >= DATE_SUB(NOW(), INTERVAL #{days} DAY)
ORDER BY publish_time DESC, id DESC
LIMIT #{limit}


WHERE status = 1
  AND id != #{contentId}
  AND EXISTS (
    SELECT 1
    FROM content_category_rel target_rel
    JOIN content_category_rel candidate_rel
      ON candidate_rel.category_code = target_rel.category_code
    WHERE target_rel.content_id = #{contentId}
      AND candidate_rel.content_id = cms_content.id
  )
ORDER BY publish_time DESC, id DESC
LIMIT #{limit}
